// File: src/components/Homepage.jsx - COMPLETE MODERN REDESIGN
import React, { useState, useEffect } from 'react';

const MeyerSignPro = () => {
  const [darkMode, setDarkMode] = useState(false);
  const [selectedService, setSelectedService] = useState('commercial');
  const [activeFilter, setActiveFilter] = useState('all');
  const [quoteData, setQuoteData] = useState({
    service: '',
    size: 'medium',
    material: 'acrylic',
    quantity: 1,
    installation: true
  });

  // Toggle dark mode
  useEffect(() => {
    if (darkMode) {
      document.documentElement.classList.add('dark');
    } else {
      document.documentElement.classList.remove('dark');
    }
  }, [darkMode]);

  // Services data
  const services = [
    {
      id: 'commercial',
      title: 'Commercial Signage',
      icon: '🏢',
      description: 'Professional business signs that maximize visibility and brand recognition',
      features: ['Channel Letters', 'Monument Signs', 'Pylon Signs', 'Awning Signs', 'LED Illuminated'],
      image: 'https://images.unsplash.com/photo-1542744095-fcf48d80b0fd?ixlib=rb-4.0.3&auto=format&fit=crop&w=1200&q=80',
      color: 'from-blue-500 to-cyan-500'
    },
    {
      id: 'vehicle',
      title: 'Vehicle Wraps',
      icon: '🚚',
      description: 'Transform vehicles into mobile billboards with premium vinyl wraps',
      features: ['Full Wraps', 'Partial Wraps', 'Fleet Graphics', 'Commercial Vehicles', 'Color Change'],
      image: 'https://images.unsplash.com/photo-1549399542-7e3f8b79c341?ixlib=rb-4.0.3&auto=format&fit=crop&w=1200&q=80',
      color: 'from-purple-500 to-pink-500'
    },
    {
      id: 'window',
      title: 'Window Graphics',
      icon: '🪟',
      description: 'Eye-catching window displays that balance visibility and aesthetics',
      features: ['Perforated Film', 'Frosted Graphics', 'Decorative Vinyl', 'Anti-Graffiti', 'UV Protected'],
      image: 'https://images.unsplash.com/photo-1513584684374-8bab748fbf90?ixlib=rb-4.0.3&auto=format&fit=crop&w=1200&q=80',
      color: 'from-emerald-500 to-teal-500'
    },
    {
      id: 'led',
      title: 'LED & Digital',
      icon: '💡',
      description: 'Dynamic digital displays and energy-efficient LED signage solutions',
      features: ['LED Message Centers', 'Digital Menu Boards', 'Video Walls', 'Architectural Lighting', 'Custom LED'],
      image: 'https://images.unsplash.com/photo-1518709268805-4e9042af2176?ixlib=rb-4.0.3&auto=format&fit=crop&w=1200&q=80',
      color: 'from-amber-500 to-orange-500'
    }
  ];

  // Portfolio projects
  const projects = [
    {
      id: 1,
      title: 'Downtown Bistro Illuminated Sign',
      category: 'commercial',
      client: 'Bella Vista Restaurant',
      location: 'New York, NY',
      before: 'https://images.unsplash.com/photo-1556909114-f6e7ad7d3136?ixlib=rb-4.0.3&auto=format&fit=crop&w=800&q=80',
      after: 'https://images.unsplash.com/photo-1549399542-7e3f8b79c341?ixlib=rb-4.0.3&auto=format&fit=crop&w=800&q=80',
      description: 'Custom illuminated channel letters with energy-efficient LED lighting'
    },
    {
      id: 2,
      title: 'Medical Center Wayfinding System',
      category: 'directional',
      client: 'Miller Medical Center',
      location: 'Chicago, IL',
      before: 'https://images.unsplash.com/photo-1551601651-2a8555f1a136?ixlib=rb-4.0.3&auto=format&fit=crop&w=800&q=80',
      after: 'https://images.unsplash.com/photo-1612349317150-e413f6a5b16d?ixlib=rb-4.0.3&auto=format&fit=crop&w=800&q=80',
      description: 'ADA-compliant wayfinding system with tactile signage'
    },
    {
      id: 3,
      title: 'Delivery Fleet Branding',
      category: 'vehicle',
      client: 'QuickDelivery Logistics',
      location: 'Miami, FL',
      before: 'https://images.unsplash.com/photo-1549399542-7e3f8b79c341?ixlib=rb-4.0.3&auto=format&fit=crop&w=800&q=80',
      after: 'https://images.unsplash.com/photo-1549399542-7e3f8b79c341?ixlib=rb-4.0.3&auto=format&fit=crop&w=800&q=80',
      description: 'Full vehicle wraps for 12-truck fleet with reflective elements'
    },
    {
      id: 4,
      title: 'Retail Store Window Graphics',
      category: 'window',
      client: 'Urban Style Boutique',
      location: 'Los Angeles, CA',
      before: 'https://images.unsplash.com/photo-1497366754035-f200968a6e72?ixlib=rb-4.0.3&auto=format&fit=crop&w=800&q=80',
      after: 'https://images.unsplash.com/photo-1513584684374-8bab748fbf90?ixlib=rb-4.0.3&auto=format&fit=crop&w=800&q=80',
      description: 'Custom perforated window film with brand graphics'
    },
    {
      id: 5,
      title: 'Corporate Headquarters Signage',
      category: 'commercial',
      client: 'TechInnovate Inc.',
      location: 'Austin, TX',
      before: 'https://images.unsplash.com/photo-1497366754035-f200968a6e72?ixlib=rb-4.0.3&auto=format&fit=crop&w=800&q=80',
      after: 'https://images.unsplash.com/photo-1542744095-fcf48d80b0fd?ixlib=rb-4.0.3&auto=format&fit=crop&w=800&q=80',
      description: 'Modern aluminum signage with integrated LED lighting'
    },
    {
      id: 6,
      title: 'Shopping Center Directory',
      category: 'directional',
      client: 'Metro Mall',
      location: 'Dallas, TX',
      before: 'https://images.unsplash.com/photo-1551601651-2a8555f1a136?ixlib=rb-4.0.3&auto=format&fit=crop&w=800&q=80',
      after: 'https://images.unsplash.com/photo-1518709268805-4e9042af2176?ixlib=rb-4.0.3&auto=format&fit=crop&w=800&q=80',
      description: 'Interactive digital directory with touchscreen interface'
    }
  ];

  // Process steps
  const processSteps = [
    { step: 1, title: 'Consultation', description: 'Free site survey & design consultation', icon: '📞', duration: '1-2 days' },
    { step: 2, title: 'Design', description: 'Custom mockups & 3D visualizations', icon: '🎨', duration: '3-5 days' },
    { step: 3, title: 'Approval', description: 'Material samples & final approvals', icon: '✓', duration: '1-2 days' },
    { step: 4, title: 'Fabrication', description: 'Precision manufacturing', icon: '⚙️', duration: '5-10 days' },
    { step: 5, title: 'Installation', description: 'Professional certified installation', icon: '📐', duration: '1-3 days' },
    { step: 6, title: 'Support', description: 'Warranty & maintenance services', icon: '🔧', duration: 'Ongoing' }
  ];

  // Testimonials
  const testimonials = [
    {
      name: 'Sarah Johnson',
      role: 'Marketing Director',
      company: 'Bella Vista Restaurant',
      content: 'The illuminated sign Meyer Sign created for our restaurant has increased foot traffic by 40%. Their attention to detail and professionalism was outstanding.',
      rating: 5,
      image: 'https://images.unsplash.com/photo-1494790108755-2616c113a1c0?ixlib=rb-4.0.3&auto=format&fit=crop&w=200&q=80'
    },
    {
      name: 'Michael Chen',
      role: 'Operations Manager',
      company: 'QuickDelivery Logistics',
      content: 'Our 12-vehicle fleet wrap project was completed on time and under budget. The quality has held up perfectly through all weather conditions.',
      rating: 5,
      image: 'https://images.unsplash.com/photo-1472099645785-5658abf4ff4e?ixlib=rb-4.0.3&auto=format&fit=crop&w=200&q=80'
    },
    {
      name: 'Jessica Williams',
      role: 'Facility Director',
      company: 'Miller Medical Center',
      content: 'The ADA-compliant wayfinding system has dramatically improved patient experience. Their team handled all permits and regulations perfectly.',
      rating: 5,
      image: 'https://images.unsplash.com/photo-1438761681033-6461ffad8d80?ixlib=rb-4.0.3&auto=format&fit=crop&w=200&q=80'
    }
  ];

  // Materials showcase
  const materials = [
    { name: 'Acrylic', durability: 'High', weather: 'Excellent', cost: '$$', description: 'Versatile and durable with excellent clarity' },
    { name: 'Aluminum', durability: 'Very High', weather: 'Excellent', cost: '$$$', description: 'Lightweight and corrosion-resistant' },
    { name: 'Stainless Steel', durability: 'Extreme', weather: 'Perfect', cost: '$$$$', description: 'Premium finish with maximum durability' },
    { name: 'PVC', durability: 'Medium', weather: 'Good', cost: '$', description: 'Cost-effective for indoor applications' },
    { name: 'Polycarbonate', durability: 'High', weather: 'Excellent', cost: '$$$', description: 'Impact-resistant and flexible' }
  ];

  // Filtered projects
  const filteredProjects = activeFilter === 'all' 
    ? projects 
    : projects.filter(project => project.category === activeFilter);

  // Calculate quote
  const calculateQuote = () => {
    const basePrice = 500;
    const sizeMultiplier = { small: 0.7, medium: 1, large: 1.5, xlarge: 2 };
    const materialMultiplier = { pvc: 0.8, acrylic: 1, aluminum: 1.5, steel: 2, polycarbonate: 1.3 };

    const price = basePrice * 
      sizeMultiplier[quoteData.size] * 
      materialMultiplier[quoteData.material] * 
      quoteData.quantity * 
      (quoteData.installation ? 1.2 : 1);

    return Math.round(price);
  };

  return (
    <div className={`min-h-screen transition-colors duration-300 ${darkMode ? 'dark bg-gray-900 text-white' : 'bg-gray-50 text-gray-900'}`}>

      {/* Navigation */}
      <nav className={`fixed w-full z-50 transition-all duration-300 ${darkMode ? 'bg-gray-900/90 backdrop-blur-md' : 'bg-white/90 backdrop-blur-md'} border-b ${darkMode ? 'border-gray-800' : 'border-gray-200'}`}>
        <div className="container mx-auto px-4 py-4">
          <div className="flex items-center justify-between">
            {/* Logo */}
            <div className="flex items-center space-x-3">
              <div className={`w-12 h-12 rounded-xl bg-gradient-to-br from-blue-600 to-purple-600 flex items-center justify-center shadow-lg`}>
                <span className="text-white font-bold text-xl">M</span>
              </div>
              <div>
                <h1 className="text-xl font-bold">Meyer Sign</h1>
                <p className="text-sm opacity-75">Professional Signage Solutions</p>
              </div>
            </div>

            {/* Desktop Navigation */}
            <div className="hidden md:flex items-center space-x-8">
              <a href="#services" className="hover:text-blue-500 transition-colors">Services</a>
              <a href="#portfolio" className="hover:text-blue-500 transition-colors">Portfolio</a>
              <a href="#process" className="hover:text-blue-500 transition-colors">Process</a>
              <a href="#materials" className="hover:text-blue-500 transition-colors">Materials</a>
              <a href="#quote" className="hover:text-blue-500 transition-colors">Get Quote</a>

              {/* Dark Mode Toggle */}
              <button 
                onClick={() => setDarkMode(!darkMode)}
                className={`p-2 rounded-full ${darkMode ? 'bg-gray-800' : 'bg-gray-200'}`}
              >
                {darkMode ? '☀️' : '🌙'}
              </button>

              <button className="bg-gradient-to-r from-blue-600 to-purple-600 text-white px-6 py-2 rounded-full font-semibold hover:shadow-lg transition-shadow">
                Contact Us
              </button>
            </div>

            {/* Mobile Menu Button */}
            <button className="md:hidden p-2">
              <svg className="w-6 h-6" fill="none" stroke="currentColor" viewBox="0 0 24 24">
                <path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M4 6h16M4 12h16M4 18h16" />
              </svg>
            </button>
          </div>
        </div>
      </nav>

      {/* Hero Section */}
      <section className="relative pt-32 pb-20 overflow-hidden">
        {/* Background Gradient */}
        <div className="absolute inset-0 bg-gradient-to-br from-blue-500/10 via-purple-500/10 to-pink-500/10"></div>

        {/* Animated Background Elements */}
        <div className="absolute top-0 left-0 w-72 h-72 bg-blue-500 rounded-full mix-blend-multiply filter blur-3xl opacity-20 animate-blob"></div>
        <div className="absolute top-0 right-0 w-72 h-72 bg-purple-500 rounded-full mix-blend-multiply filter blur-3xl opacity-20 animate-blob animation-delay-2000"></div>
        <div className="absolute bottom-0 left-1/2 w-72 h-72 bg-pink-500 rounded-full mix-blend-multiply filter blur-3xl opacity-20 animate-blob animation-delay-4000"></div>

        <div className="container mx-auto px-4 relative z-10">
          <div className="grid lg:grid-cols-2 gap-12 items-center">
            {/* Left Content */}
            <div>
              <div className="inline-flex items-center space-x-2 bg-gradient-to-r from-blue-500 to-purple-500 text-white px-4 py-2 rounded-full mb-6">
                <span>🏆 Industry Leader Since 1995</span>
              </div>

              <h1 className="text-5xl lg:text-6xl font-bold leading-tight mb-6">
                Transform Your Business With
                <span className="text-transparent bg-clip-text bg-gradient-to-r from-blue-600 to-purple-600"> Stunning Signage</span>
              </h1>

              <p className="text-xl opacity-80 mb-8">
                Professional signage solutions that enhance visibility, attract customers, and strengthen brand identity. From design to installation, we deliver excellence.
              </p>

              <div className="flex flex-col sm:flex-row gap-4">
                <button className="bg-gradient-to-r from-blue-600 to-purple-600 text-white px-8 py-4 rounded-xl font-semibold text-lg hover:shadow-xl transition-shadow hover:scale-105 transform duration-300">
                  Request Free Design Mockup
                </button>
                <button className="border-2 border-gray-300 dark:border-gray-700 px-8 py-4 rounded-xl font-semibold text-lg hover:border-blue-500 transition-colors">
                  View Our Portfolio →
                </button>
              </div>

              {/* Stats */}
              <div className="mt-12 grid grid-cols-3 gap-6">
                {[
                  { number: '500+', label: 'Projects Completed' },
                  { number: '98%', label: 'Client Satisfaction' },
                  { number: '24h', label: 'Quote Response' }
                ].map((stat, idx) => (
                  <div key={idx} className="text-center">
                    <div className="text-3xl font-bold bg-gradient-to-r from-blue-600 to-purple-600 text-transparent bg-clip-text">{stat.number}</div>
                    <div className="text-sm opacity-75">{stat.label}</div>
                  </div>
                ))}
              </div>
            </div>

            {/* Right - Interactive Service Preview */}
            <div className="relative">
              <div className="bg-white dark:bg-gray-800 rounded-2xl shadow-2xl overflow-hidden">
                <div className="p-6">
                  <h3 className="text-xl font-bold mb-4">Interactive Service Preview</h3>

                  {/* Service Selector */}
                  <div className="flex space-x-2 mb-6">
                    {services.map(service => (
                      <button
                        key={service.id}
                        onClick={() => setSelectedService(service.id)}
                        className={`px-4 py-2 rounded-lg transition-all ${selectedService === service.id ? 'bg-gradient-to-r ' + service.color + ' text-white' : 'bg-gray-100 dark:bg-gray-700'}`}
                      >
                        {service.icon}
                      </button>
                    ))}
                  </div>

                  {/* Service Preview */}
                  <div className="relative h-64 rounded-xl overflow-hidden mb-4">
                    <img 
                      src={services.find(s => s.id === selectedService).image} 
                      alt="Service Preview"
                      className="w-full h-full object-cover"
                    />
                    <div className="absolute inset-0 bg-gradient-to-t from-black/50 to-transparent"></div>
                    <div className="absolute bottom-4 left-4 text-white">
                      <div className="text-lg font-bold">{services.find(s => s.id === selectedService).title}</div>
                      <div className="text-sm opacity-90">{services.find(s => s.id === selectedService).description}</div>
                    </div>
                  </div>

                  {/* Features */}
                  <div className="grid grid-cols-2 gap-2">
                    {services.find(s => s.id === selectedService).features.slice(0, 4).map((feature, idx) => (
                      <div key={idx} className="flex items-center space-x-2 text-sm">
                        <div className="w-2 h-2 bg-blue-500 rounded-full"></div>
                        <span>{feature}</span>
                      </div>
                    ))}
                  </div>
                </div>
              </div>

              {/* Floating Element */}
              <div className="absolute -bottom-6 -right-6 bg-gradient-to-r from-blue-600 to-purple-600 text-white p-6 rounded-2xl shadow-xl">
                <div className="text-2xl font-bold">Free 3D Mockup</div>
                <div className="text-sm">With Every Quote</div>
              </div>
            </div>
          </div>
        </div>
      </section>

      {/* Services Section */}
      <section id="services" className="py-20">
        <div className="container mx-auto px-4">
          <div className="text-center mb-16">
            <h2 className="text-4xl font-bold mb-4">Our Premium Services</h2>
            <p className="text-xl opacity-75 max-w-3xl mx-auto">
              Comprehensive signage solutions tailored to your business needs
            </p>
          </div>

          <div className="grid md:grid-cols-2 lg:grid-cols-4 gap-6">
            {services.map(service => (
              <div 
                key={service.id}
                className={`bg-white dark:bg-gray-800 rounded-2xl overflow-hidden shadow-lg hover:shadow-2xl transition-all duration-300 hover:scale-105 cursor-pointer ${selectedService === service.id ? 'ring-2 ring-blue-500' : ''}`}
                onClick={() => setSelectedService(service.id)}
              >
                <div className={`h-3 bg-gradient-to-r ${service.color}`}></div>
                <div className="p-6">
                  <div className="flex items-center justify-between mb-4">
                    <div className="text-3xl">{service.icon}</div>
                    <div className={`px-3 py-1 rounded-full text-xs font-semibold bg-gradient-to-r ${service.color} text-white`}>
                      Popular
                    </div>
                  </div>
                  <h3 className="text-xl font-bold mb-3">{service.title}</h3>
                  <p className="text-gray-600 dark:text-gray-300 mb-4">{service.description}</p>
                  <div className="space-y-2">
                    {service.features.slice(0, 3).map((feature, idx) => (
                      <div key={idx} className="flex items-center text-sm">
                        <svg className="w-4 h-4 text-green-500 mr-2" fill="currentColor" viewBox="0 0 20 20">
                          <path fillRule="evenodd" d="M16.707 5.293a1 1 0 010 1.414l-8 8a1 1 0 01-1.414 0l-4-4a1 1 0 011.414-1.414L8 12.586l7.293-7.293a1 1 0 011.414 0z" clipRule="evenodd" />
                        </svg>
                        {feature}
                      </div>
                    ))}
                  </div>
                  <button className="w-full mt-6 py-3 rounded-lg bg-gray-100 dark:bg-gray-700 hover:bg-gray-200 dark:hover:bg-gray-600 transition-colors">
                    Learn More →
                  </button>
                </div>
              </div>
            ))}
          </div>
        </div>
      </section>

      {/* Portfolio Gallery */}
      <section id="portfolio" className={`py-20 ${darkMode ? 'bg-gray-800' : 'bg-gray-100'}`}>
        <div className="container mx-auto px-4">
          <div className="text-center mb-12">
            <h2 className="text-4xl font-bold mb-4">Featured Projects</h2>
            <p className="text-xl opacity-75 mb-8">Real projects, real impact</p>

            {/* Filter Buttons */}
            <div className="flex flex-wrap justify-center gap-3 mb-12">
              {['all', 'commercial', 'vehicle', 'window', 'directional'].map(filter => (
                <button
                  key={filter}
                  onClick={() => setActiveFilter(filter)}
                  className={`px-6 py-3 rounded-full transition-all ${activeFilter === filter ? 'bg-gradient-to-r from-blue-600 to-purple-600 text-white' : 'bg-white dark:bg-gray-700 hover:bg-gray-100 dark:hover:bg-gray-600'}`}
                >
                  {filter.charAt(0).toUpperCase() + filter.slice(1)}
                </button>
              ))}
            </div>
          </div>

          {/* Projects Grid */}
          <div className="grid md:grid-cols-2 lg:grid-cols-3 gap-8">
            {filteredProjects.map(project => (
              <div 
                key={project.id} 
                className="bg-white dark:bg-gray-800 rounded-2xl overflow-hidden shadow-lg hover:shadow-2xl transition-all duration-300 group"
              >
                {/* Before/After Slider */}
                <div className="relative h-64 overflow-hidden">
                  <div className="absolute inset-0 flex">
                    <img 
                      src={project.before} 
                      alt="Before" 
